var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가도 가도 끝이 없네요...... 아지트엔 언제쯤 도착하나요?","JPN":"歩いても歩いても着きませんね……アジトにはいつ頃到着しますの？","ENG":"It feels we've been walking for hours. How far away are we from their hideout?","TWN":"不管怎麼走，就是沒有盡頭啊……還要多久才能到達他們的基地啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"조금만 참아. 얼마 안 남았어.","JPN":"もうちょっと頑張ってよ。あと少しだからさ。","ENG":"Keep walking, Regina. We're almost there.","TWN":"再忍耐一下，就要到了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러니까 이쯤에서 잠깐 쉬면서 배 좀 채울까?","JPN":"じゃあ、そろそろちょっと休んで何か食べる？","ENG":"Or we can take a short break here and fill our tummies.","TWN":"那我們要不要在這裡稍微休息一下，填飽肚子如何？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금 음식이 목구멍으로 넘어가요?","JPN":"この状況で食べ物がのどを通ると思います？","ENG":"How could you eat anything at a time like this?","TWN":"妳還可以吃得下東西？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"곧 싸워야 하잖아요. 전 긴장돼서 헛구역질이 나올 지경이라고요.","JPN":"戦いの時が迫っているのです。私は緊張して吐き気がしそうなくらいですわ。","ENG":"We're about to go into battle. I'm so nervous that I feel like I'm going to throw up.","TWN":"馬上就要戰鬥了吧，我緊張得都要吐出來了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"싸우기 전에는 배를 든든하게 채워야 하는 법. 노련한 용병에겐 상식이지.","JPN":"戦いの前だからこそ、しっかり食べとかないと。ベテラン傭兵の常識だよ。","ENG":"You can't fight with an empty belly. It's common sense among experienced mercenaries.","TWN":"打架前當然要把肚子填飽啊，這對經驗豐富的傭兵來說可是常識。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 노련하지도 않고 용병도 아니에요. 전혀 공감 못하겠네요.","JPN":"私はベテランでも傭兵でもありませんから。全く共感できませんわ。","ENG":"I'm neither experienced nor a mercenary. I can hardly relate.","TWN":"我既沒有經驗豐富，也不是傭兵，完全無法體會呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 레지나는 냉혈한이구나?","JPN":"ほんと、レジーナって冷たいよね。","ENG":"You just don't go with the flow, do you?","TWN":"哎呀，蕾佳娜可真冷漠啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"대학에서도 교수님들하고만 친하고 친구는 없지?","JPN":"大学でも教授とは仲良くても、友達はいないでしょ？","ENG":"You must be one of those types who's close with professors but doesn't have a single friend.","TWN":"妳在大學肯定只跟教授比較好，但完全沒有朋友吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"윽...... 그, 그걸 어떻게......?","JPN":"うっ……ど、どうしてそれを……？","ENG":"Oh... H-how did you know?","TWN":"唔……妳、妳怎麼知道……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이번 기회에 다른 사람들이랑 친해지는 요령을 배워 둬. 싸울 때 친구 말고 누굴 믿겠어.","JPN":"このチャンスに、他の人と仲良くなる方法を学んだ方がいいよ。戦いで頼れるのは仲間だけだから。","ENG":"Use this opportunity to learn how to make some friends. Friends are the ones that watch your back in a fight.","TWN":"趁這個機會，來學學要怎麼和其他人打好關係的技巧吧？戰鬥的時候，不相信朋友還能相信誰啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시나 해서 묻는데, 당신에게 친구란 뭐죠?","JPN":"念のために教えてほしいのですが、あなたにとって仲間とは何ですの？","ENG":"Just out of curiosity, what does 'friend' mean to you?","TWN":"以防萬一問一下，對妳來說朋友是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"여차할 때 쓸 수 있는 고기방패.","JPN":"ピンチの時に便利な肉の盾。","ENG":"A meat shield that I can use in times of emergency.","TWN":"發生意外時的肉盾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당장 출발하죠. 서두르면 날이 밝기 전에 저택으로 돌아갈 수 있을 거예요.","JPN":"すぐに出発しましょう。急げば夜が明ける前に邸宅に戻れるはずですわ。","ENG":"Let's just go. If we hurry, we'll be able to get back to the mansion before dawn.","TWN":"馬上出發吧。我們快一點的話，應該可以在天亮之前回到宅邸。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"나야 별로 상관없지만 에델은 많이 실망할 것 같은데?","JPN":"アタシは別に気にしないけど、エデルはきっとガッカリすると思うよ。","ENG":"I'm okay with it, but Edel will be very disappointed.","TWN":"我是沒什麼關係啦，但艾瑟兒好像會很失望的樣子喔？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델? 에델이 어쨌다고 그래요?","JPN":"エデル？　エデルがどうかしましたか？","ENG":"Edel? What about her?","TWN":"艾瑟兒？艾瑟兒怎麼了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어머나, 숲 속에서 일행들과 단란하게 식사라니 멋진 생각이에요.","JPN":"あら、森の中でみんな仲良く食事なんて素敵なアイデアですね。","ENG":"Oh, a light meal with friends in the forest? That's a wonderful idea.","TWN":"哎呀，在森林裡大家聚在一起用餐什麼的，我們覺得很好呀。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"피크닉 세트를 챙겨 오길 잘했어요. 소풍 분위기가 물씬 나네요. 후훗.","JPN":"ピクニックセットを持ってきて正解でした。遠足みたいで楽しいです。ふふっ。","ENG":"It was really a good idea to bring the picnic package. It sure feels like picnic, doesn't it? Fu fu.","TWN":"幸好我們把野餐餐具也帶來了，很有郊遊的氣氛呢，呵呵。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};